sql:
SELECT COUNT(subsidy_id) AS subsidy_count
FROM subsidies
WHERE year = 2020;

SELECT company_name, location
FROM corporations
WHERE revenue < (SELECT AVG(revenue) FROM corporations);

external_knowledge:
- 'MEGADEAL' is a metaphorical term for a significant subsidy provided to corporations;
- 'digital fortresses' represents the official websites of the corporations;
- 'realm of 2022' is another way of saying the year 2022;
- 'golden parachute' symbolizes substantial financial support which aids in achieving significant economic growth.

sql:
SELECT corporations.ceo, subsidies.subsidy_value
FROM corporations
INNER JOIN subsidies ON corporations.corp_id = subsidies.corp_id;

SELECT corp_id, company_name, location, industry, revenue
FROM corporations
WHERE industry = 'Financial';

external_knowledge:
- Major players: Notable corporations in the industry; 
- Unusually generous subsidies: Subsidies that are significantly above the average subsidy value; 
- Details of subsidies: Include company name, location, year, source, type, value, and impacts (industry, environmental, social); 
- Surpassed the typical average: The subsidy value is more than the square of the average subsidy value.

sql:
SELECT company_name
FROM corporations
WHERE revenue > (SELECT AVG(revenue) FROM corporations);

SELECT UPPER(company_name) AS upper_case_name
FROM corporations
WHERE corp_id > 1000;

SELECT COUNT(corp_id) 
FROM corporations 
WHERE location = 'New York' AND industry = 'Financial Services';

external_knowledge:
- "sectors with relatively fewer players" implies industries with fewer than 50 companies; 
- "financial assistance" refers to subsidies;
- "the average amount of aid" corresponds to the average subsidy value.

sql:
SELECT year, SUM(subsidy_value) AS total_subsidy_value
FROM subsidies
GROUP BY year;

SELECT COUNT(DISTINCT corp_id) AS unique_corporations
FROM subsidies
WHERE year = 2020;

SELECT subsidy_id, corp_id, year, subsidy_value, loan_bailout_value, subsidy_type
FROM subsidies
WHERE subsidy_type = 'MEGADEAL' AND subsidy_source = 'local';
